// Calculate review priority and urgency for each document
const document = $input.first().json;

const status = document.status;
const priority = document.priority || 'medium';
const validationScore = document.validation_score || 0;
const confidenceScore = document.confidence_score || 0;
const errors = document.validation_errors || [];
const warnings = document.validation_warnings || [];

const now = new Date();
const receivedAt = new Date(document.received_at);
const ageInHours = (now - receivedAt) / (1000 * 60 * 60);

// Calculate review urgency score (0-100)
let urgencyScore = 50;  // Base score

// Factor in priority level
if (priority === 'urgent') {
  urgencyScore += 30;
} else if (priority === 'high') {
  urgencyScore += 20;
} else if (priority === 'medium') {
  urgencyScore += 10;
}

// Factor in validation score (lower = more urgent)
if (validationScore < 50) {
  urgencyScore += 20;
} else if (validationScore < 70) {
  urgencyScore += 10;
}

// Factor in confidence score (lower = more urgent)
if (confidenceScore < 60) {
  urgencyScore += 15;
} else if (confidenceScore < 80) {
  urgencyScore += 5;
}

// Factor in number of errors
if (errors.length > 3) {
  urgencyScore += 15;
} else if (errors.length > 0) {
  urgencyScore += 5;
}

// Factor in document age (older = more urgent)
if (ageInHours > 48) {
  urgencyScore += 20;
} else if (ageInHours > 24) {
  urgencyScore += 10;
} else if (ageInHours > 12) {
  urgencyScore += 5;
}

// Cap at 100
urgencyScore = Math.min(urgencyScore, 100);

// Determine SLA deadline based on priority
let slaDeadline = null;
const slaHours = {
  urgent: 4,
  high: 8,
  medium: 24,
  low: 72
};

const hoursUntilDeadline = slaHours[priority] || 24;
slaDeadline = new Date(receivedAt.getTime() + (hoursUntilDeadline * 60 * 60 * 1000));

const isOverdue = now > slaDeadline;

// Prepare review queue item
const reviewItem = {
  document_id: document.document_id,
  document_uuid: document.document_uuid,
  client_id: document.client_id,
  original_filename: document.original_filename,
  storage_path: document.storage_path,
  category: document.category || 'unknown',
  priority: priority,
  urgency_score: urgencyScore,
  status: status,
  validation_score: validationScore,
  confidence_score: confidenceScore,
  errors: errors,
  warnings: warnings,
  age_hours: Math.round(ageInHours * 10) / 10,
  sla_deadline: slaDeadline.toISOString(),
  is_overdue: isOverdue,
  hours_until_deadline: Math.round((slaDeadline - now) / (1000 * 60 * 60) * 10) / 10,
  review_reason: determineReviewReason(status, validationScore, confidenceScore, errors),
  review_instructions: generateReviewInstructions(document),
  queue_added_at: now.toISOString()
};

return [{ json: reviewItem }];

// Helper function to determine review reason
function determineReviewReason(status, validationScore, confidenceScore, errors) {
  const reasons = [];

  if (status === 'validation_failed') {
    reasons.push('Validation failed');
  }
  if (status === 'pending_manual_review') {
    reasons.push('Manual review required');
  }
  if (status === 'classified_low_confidence') {
    reasons.push('Low classification confidence');
  }
  if (validationScore < 70) {
    reasons.push('Low validation score');
  }
  if (confidenceScore < 70) {
    reasons.push('Low extraction confidence');
  }
  if (errors.length > 0) {
    reasons.push(`${errors.length} validation error(s)`);
  }

  return reasons.length > 0 ? reasons.join(', ') : 'Manual review required';
}

// Helper function to generate review instructions
function generateReviewInstructions(document) {
  const instructions = [];

  if (document.category === 'invoice') {
    instructions.push('Verify invoice number matches records');
    instructions.push('Check total amount accuracy');
    instructions.push('Confirm vendor details');
  } else if (document.category === 'contract') {
    instructions.push('Review contract terms');
    instructions.push('Verify party information');
    instructions.push('Check dates and durations');
  } else if (document.category === 'resume') {
    instructions.push('Review candidate information');
    instructions.push('Verify contact details');
    instructions.push('Assess skills and experience');
  }

  if (document.validation_errors && document.validation_errors.length > 0) {
    instructions.push('Address validation errors');
  }
  if (document.validation_warnings && document.validation_warnings.length > 0) {
    instructions.push('Review validation warnings');
  }

  return instructions.join('; ');
}

// Generate review queue summary report
const allReviewItems = $input.all().map(item => item.json);

const now = new Date();

// Calculate statistics
const totalItems = allReviewItems.length;
const overdueItems = allReviewItems.filter(item => item.is_overdue).length;
const urgentItems = allReviewItems.filter(item => item.priority === 'urgent').length;
const highPriorityItems = allReviewItems.filter(item => item.priority === 'high').length;

const avgUrgency = totalItems > 0 ? 
  allReviewItems.reduce((sum, item) => sum + item.urgency_score, 0) / totalItems : 0;

// Group by status
const byStatus = {
  validation_failed: allReviewItems.filter(item => item.status === 'validation_failed').length,
  pending_manual_review: allReviewItems.filter(item => item.status === 'pending_manual_review').length,
  classified_low_confidence: allReviewItems.filter(item => item.status === 'classified_low_confidence').length
};

// Group by category
const byCategory = {};
allReviewItems.forEach(item => {
  const cat = item.category || 'unknown';
  byCategory[cat] = (byCategory[cat] || 0) + 1;
});

const summary = {
  generated_at: now.toISOString(),
  total_documents_needing_review: totalItems,
  overdue_documents: overdueItems,
  urgent_documents: urgentItems,
  high_priority_documents: highPriorityItems,
  average_urgency_score: Math.round(avgUrgency * 10) / 10,
  breakdown_by_status: byStatus,
  breakdown_by_category: byCategory,
  documents: allReviewItems.map(item => ({
    document_id: item.document_id,
    document_uuid: item.document_uuid,
    filename: item.original_filename,
    category: item.category,
    priority: item.priority,
    urgency_score: item.urgency_score,
    is_overdue: item.is_overdue,
    hours_until_deadline: item.hours_until_deadline,
    review_reason: item.review_reason
  }))
};

return [{ json: summary }];
